mapper.delete:
UPDATE esg.tb_training_result_report
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

DELETE FROM esg.tb_training_result_report_hr
WHERE write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

mapper.select:
SELECT *
FROM esg.tb_training_result_report
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

select t1.doc_no
from esg.tb_training_result_report t1
where t1.use_yn = 'Y'
    and t1.write_year = #{writeYear}
    and t1.comp_id = #{compId}
    and substring(t1.training_date from 5 for 2) = #{searchText}
order by t1.training_date asc
